```python
class NQueensSolver:
    def __init__(self, n):
        self.n = n
        self.board = [['.' for _ in range(n)] for _ in range(n)]

    def solve(self):
        self._backtrack()

    def _backtrack(self):
        for i in range(self.n):
            for j in range(self.n):
                if self.board[i][j] == '.':
                    for c in map(str, range(1, self.n + 1)):
                        if self._is_valid(i, j, c):
                            self.board[i][j] = c
                            if self._backtrack():
                                return True
                            self.board[i][j] = '.'
                    return False
        return True

    def _is_valid(self, row, col, c):
        for i in range(self.n):
            if self.board[i][col] == c or self.board[row][i] == c:
                return False
        block_row, block_col = 3 * (row // 3), 3 * (col // 3)
        for i in range(3):
            for j in range(3):
                if self.board[block_row + i][block_col + j] == c:
                    return False
        return True
