class TodoList extends React.Component {
  constructor(props) {
    super(props);
    this.state = { items: [], newItemText: '', completedItems: [] };
  }

  handleTextChange = (event) => {
    this.setState({ newItemText: event.target.value });
  }

  handleAddItem = () => {
    if (this.state.newItemText !== '') {
      this.setState(prevState => ({
        items: [...prevState.items, this.state.newItemText],
        completedItems: [...prevState.completedItems, this.state.newItemText],
        newItemText: ''
      }));
