#include <stdexcept>

class VectorMaths {
public:
    VectorMaths(const std::vector<int>& values) : m_values(values) {}

    VectorMaths add(const VectorMaths& other) {
        if (m_values.size() != other.m_values.size()) {
            throw std::invalid_argument("Vectors must have the same dimension for addition.");
        }
        std::vector<int> result(m_values.size(), 0);
        for (size_t i = 0; i < m_values.size(); i++) {
            result[i] += m_values[i] + other.m_values[i];
        }
        return VectorMaths(result);
    }

    VectorMaths multiply(const VectorMaths& other) {
        if (m_values.size() != other.m_values.size() || m_values.size() != other.m_values.size()) {
            throw std::invalid_argument("Vectors must have the same dimension for multiplication.");
        }
        std::vector<int> result(m_values.size(), 0);
        for (size_t i = 0; i < m_values.size(); i++) {
            for (size_t j = 0; j < m_values.size(); j++) {
                result[i] += m_values[i] * other.m_values[j];
            }
        }
        return VectorMaths(result);
    }

    double magnitude() const {
        return std::sqrt(m_values[0] * m_values[0] + m_values[1] * m_values[1]);
    }

    void display() const {
        std::cout << "Vector: " << m_values[0] << " " << m_values[1] << std::endl;
    }

private:
    std::vector<int> m_values;
};
