void array_delete(int **array, int *size, int index) {
    if (index < 0 || index >= *size) {
        fprintf(stderr, "Index out of bounds\n");
        return;
    }
    *array = (int *)realloc(*array, (*size - 1) * sizeof(int));
    if (*array == NULL) {
        perror("Realloc failed");
        exit(EXIT_FAILURE);
