use serde::{Deserialize, Serialize};
use serde_json::{json, Value};
use std::{collections::HashMap, sync::Mutex};

#[derive(Serialize, Deserialize)]
struct UserData {
    username: String,
    email: String,
}

lazy_static! {
    static ref DATABASE: Mutex<HashMap<String, UserData>> = Mutex::new(HashMap::new());
}

fn update_user(id: String, update_data: UserData) -> Result<Value, String> {
    let db = DATABASE.lock().unwrap();
    let user_data = db.get(&id).cloned();

    if user_data.is_none() {
        return Err(format!("User not found with ID {}", id));
    }

    let user_data = user_data.unwrap();
    if update_data.username != "" && user_data.username != update_data.username {
        if db.contains_key(&update_data.username) {
            return Err(format!("Username already exists"));
        }
    }
    if update_data.email != "" && user_data.email != update_data.email {
        if db.contains_key(&update_data.email) {
            return Err(format!("Email already exists"));
        }
    }

    db.insert(id.clone(), update_data);
    Ok(json!({"message": "User updated successfully"}))
}
