            throw new IllegalArgumentException("Transaction amount must be positive.");
        }
        if (!type.equals("deposit") && !type.equals("withdrawal")) {
            throw new IllegalArgumentException("Invalid transaction type. Must be 'deposit' or 'withdrawal'.");
        }
        this.amount = amount;
        this.type = type;
    }

    /**
     * Processes the transaction on the account.
     * 
     * @param account the account to process the transaction on
     * @throws InsufficientFundsException if there are insufficient funds
     */
    public void process(Account account) throws InsufficientFundsException {
        if (type.equals("deposit")) {
            account.deposit(amount);
        } else {
            account.withdraw(amount);
        }
    }

    /**
     * Returns a string representation of the transaction.
     * 
     * @return a string representation of the transaction
     */
    @Override
    public String toString() {
        return type + " of " + amount;
    }
}

/**
