```cpp
#include <iostream>
#include <vector>

class DynamicArray {
private:
    std::vector<int> arr;
    int capacity;

public:
    DynamicArray() : capacity(0) {}

    bool add(int element) {
        if (arr.size() == capacity) {
            capacity *= 2;
            arr.resize(capacity);
        }
        arr.push_back(element);
        return true;
    }

    int get(int index) const {
        if (index >= 0 && index < arr.size()) {
            return arr[index];
        }
        throw std::out_of_range("Index out of bounds");
    }

    int size() const {
        return arr.size();
    }

    void resize(int newCapacity) {
        if (newCapacity > capacity) {
            capacity = newCapacity;
            arr.resize(capacity);
        }
    }
};

int main() {
    DynamicArray dynArray;
    std::cout << "Size: " << dynArray.size() << std::endl;

    dynArray.add(10);
    dynArray.add(20);
    dynArray.add(30);
    std::cout << "Size: " << dynArray.size() << std::endl;
    std::cout << "Element at index 1: " << dynArray.get(1) << std::endl;

